// restaurant-settings.ts
import { Component, OnInit, OnDestroy, inject, ViewChild, ElementRef } from '@angular/core';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { debounceTime, filter, Subject, takeUntil } from 'rxjs';
import { RestaurantPhoto, Shift } from '../../../models';
import { SupabaseService } from '../../../services/Base/supabase.service';
import { ShiftService } from '../../../services/shift.service';
import { AuthService } from '../../../services/Base/auth.service';
import { RestaurantPublicService } from '../../../services/restaurant-public.service';
import { LucideAngularModule } from 'lucide-angular';

// Tipo per i dati del form turno (senza i campi automatici)
type ShiftFormData = Omit<Shift, 'id' | 'restaurant_id' | 'created_at' | 'updated_at'>;

@Component({
  selector: 'app-restaurant-settings',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, FormsModule, LucideAngularModule],
  templateUrl: './restaurant-settings.html',
  styleUrls: ['./restaurant-settings.css']
})
export class RestaurantSettings implements OnInit, OnDestroy {
  // Form
  settingsForm!: FormGroup;
  canEditSettings = false;

  // State
  loading = false;
  loadingPhotos = false;
  restaurantId: string | null = null;

  // UI State
  showShiftModal = false;
  editingShift: 'new' | number | null = null;
  currentSlotIndex: number | null = null;
  fullscreenPhoto: string | null = null;
  currentPhotoIndex: number | null = null;
  canManagePhotos = false;

  // Info Aggiuntive
  paymentOptions = [
    { value: 'cash', label: 'Contanti' },
    { value: 'credit_card', label: 'Carta di credito' },
    { value: 'debit_card', label: 'Bancomat' },
    { value: 'satispay', label: 'Satispay' },
    { value: 'paypal', label: 'PayPal' }
  ];

  foodOptions = [
    { value: 'vegan', label: 'Vegan' },
    { value: 'gourmet', label: 'Gourmet' },
    { value: 'fish', label: 'Pesce' },
    { value: 'meat', label: 'Carne' }
  ];

  // Opzioni parcheggio (singola scelta)
  parkingOptions = [
    { value: 'free_private', label: 'Parcheggio privato gratuito' },
    { value: 'paid_private', label: 'Parcheggio privato a pagamento' },
    { value: 'free_public', label: 'Parcheggio pubblico gratuito' },
    { value: 'paid_public', label: 'Parcheggio pubblico a pagamento' },
    { value: 'none', label: 'Nessun parcheggio' }
  ];

  // Tipi di cucina (multipla scelta)
  cuisineOptions = [
    { value: 'italian', label: 'Italiana' },
    { value: 'pizza', label: 'Pizzeria' },
    { value: 'chinese', label: 'Cinese' },
    { value: 'japanese', label: 'Giapponese' },
    { value: 'mediterranean', label: 'Mediterranea' },
    { value: 'vegan', label: 'Vegan' },
    { value: 'vegetarian', label: 'Vegetariana' },
    { value: 'gluten_free', label: 'Senza glutine' },
    { value: 'fish', label: 'Pesce' },
    { value: 'meat', label: 'Carne' },
    { value: 'gourmet', label: 'Gourmet' }
    // aggiungi tutte le opzioni che desideri
  ];

  // Data
  shifts: Shift[] = [];
  photos: (RestaurantPhoto | null)[] = Array(8).fill(null);
  currentCoverUrl: string | null = null;

  // Constants
  weekDays = ['Lunedì', 'Martedì', 'Mercoledì', 'Giovedì', 'Venerdì', 'Sabato', 'Domenica'];

  // ViewChild
  @ViewChild('fileInput') fileInput!: ElementRef<HTMLInputElement>;

  // Services
  private fb = inject(FormBuilder);
  private supabaseService = inject(SupabaseService);
  private shiftService = inject(ShiftService);
  private authService = inject(AuthService);
  private restaurantService = inject(RestaurantPublicService);

  private destroy$ = new Subject<void>();
  private supabaseClient = this.supabaseService.getSupabaseClient();
  private autoSaveTrigger = new Subject<void>();

  // Shift management properties
  currentShift: ShiftFormData = this.createEmptyShift();

  // Danger zone
  showDeleteRestaurantConfirm = false;
  deleteRestaurantLoading = false;
  deleteRestaurantError = '';

  ngOnInit() {
    this.initForm();
    this.setupSubscriptions();
    this.loadInitialData();
    this.canEditSettings = this.authService.hasPermission('manage_restaurant_settings');
    if (!this.canEditSettings) {
      this.settingsForm.disable();
    }

  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

private initForm() {
  this.settingsForm = this.fb.group({
    accepts_delivery: [false],
    accepts_takeaway: [false],
    allow_table_selection: [false],
    is_active: [true],
    additional_info: this.fb.group({
      parking: [''],
      accepted_payments: [[]],  
      wifi: this.fb.group({
        ssid: [''],
        password: ['']
      }),
      food_info: this.fb.group({
        vegan: [false],
        gourmet: [false],
        fish: [false],
        meat: [false]
      }),
      cuisine_types: [[]]          
    })
  });
}

  private setupSubscriptions() {
    // Sottoscrizione ai turni (ora data$)
    this.shiftService.data$
      .pipe(takeUntil(this.destroy$))
      .subscribe((shifts: Shift[]) => {
        this.shifts = shifts;
        // Se desideri che le modifiche ai turni inneschino l'autosalvataggio del form,
        // lascia la riga seguente, altrimenti rimuovila.
        // this.triggerAutoSave();
      });

    this.settingsForm.valueChanges
      .pipe(
        takeUntil(this.destroy$),
        debounceTime(1500),
        filter(() => this.settingsForm.valid && !!this.restaurantId)
      )
      .subscribe(() => this.autoSaveChanges());

    this.autoSaveTrigger
      .pipe(
        takeUntil(this.destroy$),
        debounceTime(1000),
        filter(() => !!this.restaurantId)
      )
      .subscribe(() => this.autoSaveChanges());
  }

  private triggerAutoSave(): void {
    this.autoSaveTrigger.next();
  }

  private async loadInitialData() {
    this.loading = true;
    try {
      this.restaurantId = await this.restaurantService.getCurrentRestaurantId();
      if (!this.restaurantId) throw new Error('Nessun ristorante associato all\'utente');

      await this.loadRestaurantData();
      await this.shiftService.loadData(); // carica i turni

      this.canManagePhotos = this.authService.hasPermission('manage_restaurant_settings') 
  || this.authService.hasPermission('manage_dish_photos');
      if (this.canManagePhotos) {
        await this.loadRestaurantPhotos();
      }
    } catch (error: any) {
      console.error('Errore caricamento iniziale:', error);
      alert('Errore durante il caricamento dei dati: ' + error.message);
    } finally {
      this.loading = false;
    }
  }

private async loadRestaurantData() {
  const restaurant = await this.restaurantService.loadCurrentRestaurant();
  if (!restaurant) throw new Error('Ristorante non trovato');
  this.currentCoverUrl = restaurant.cover_image_url ?? null;

  this.settingsForm.patchValue({
    accepts_delivery: restaurant.accepts_delivery,
    accepts_takeaway: restaurant.accepts_takeaway,
    allow_table_selection: restaurant.allow_table_selection,
    is_active: restaurant.is_active,
    additional_info: {
      parking: restaurant.additional_info?.parking || '',
      accepted_payments: restaurant.additional_info?.accepted_payments || [],
      wifi: restaurant.additional_info?.wifi || { ssid: '', password: '' },
      food_info: restaurant.additional_info?.food_info || { vegan: false, gourmet: false, fish: false, meat: false },
      cuisine_types: restaurant.additional_info?.cuisine_types || []
    }
  });
}

  private async loadRestaurantPhotos() {
    if (!this.restaurantId) return;

    this.loadingPhotos = true;
    try {
      const photos = await this.supabaseService.getRestaurantPhotos(this.restaurantId);
      this.photos = Array(8).fill(null);

      photos.forEach(photo => {
        const index = photo.display_order - 1;
        if (index >= 0 && index < 8) {
          if (!photo.url && photo.file_path) {
            const { data: { publicUrl } } = this.supabaseClient.storage
              .from('restaurant-images')
              .getPublicUrl(photo.file_path);
            photo.url = publicUrl;
          }
          this.photos[index] = photo;
        }
      });
    } catch (error) {
      console.error('Errore caricamento foto:', error);
    } finally {
      this.loadingPhotos = false;
    }
  }

  private async autoSaveChanges(): Promise<void> {
    if (this.settingsForm.invalid || !this.restaurantId) return;
    try {
      await this.saveFormData();
      console.log('✅ Salvataggio automatico completato');
    } catch (error) {
      console.error('❌ Errore salvataggio automatico:', error);
    }
  }

  async onSubmit() {
    if (this.settingsForm.invalid || !this.restaurantId) return;

    this.loading = true;
    try {
      await this.saveFormData();
      alert('Impostazioni salvate con successo!');
    } catch (err: any) {
      console.error('❌ Errore salvataggio:', err);
      alert('Errore durante il salvataggio: ' + err.message);
    } finally {
      this.loading = false;
    }
  }

private async saveFormData(): Promise<void> {
  const formValue = this.settingsForm.value;
  const success = await this.restaurantService.updateRestaurant(this.restaurantId!, {
    accepts_delivery: formValue.accepts_delivery,
    accepts_takeaway: formValue.accepts_takeaway,
    allow_table_selection: formValue.allow_table_selection,
    is_active: formValue.is_active,
    additional_info: formValue.additional_info
  });
  if (!success) {
    throw new Error('Salvataggio fallito: verifica i permessi o contatta il supporto');
  }
}

  // ==================== SHIFT MANAGEMENT ====================

  private createEmptyShift(): ShiftFormData {
    return {
      name: '',
      start_time: '12:00',
      end_time: '15:00',
      days_of_week: [1, 2, 3, 4, 5, 6, 7],
      is_active: true
    };
  }

  addNewShift() {
    this.editingShift = 'new';
    this.currentShift = this.createEmptyShift();
    this.showShiftModal = true;
  }

  editShift(index: number) {
    this.editingShift = index;
    const shift = this.shifts[index];
    this.currentShift = {
      name: shift.name,
      start_time: shift.start_time,
      end_time: shift.end_time,
      days_of_week: [...shift.days_of_week],
      is_active: shift.is_active
    };
    this.showShiftModal = true;
  }

  async saveShift() {
    if (!this.isCurrentShiftValid() || !this.restaurantId) return;

    this.loading = true;
    try {
      if (this.editingShift === 'new') {
        const created = await this.shiftService.create(this.currentShift);
        if (!created) throw new Error('Creazione fallita');
        alert('Turno creato con successo!');
      } else if (typeof this.editingShift === 'number') {
        const shiftId = this.shifts[this.editingShift].id;
        const success = await this.shiftService.update(shiftId, this.currentShift);
        if (!success) throw new Error('Aggiornamento fallito');
        alert('Turno aggiornato con successo!');
      }
      this.closeShiftModal();
    } catch (err: any) {
      alert('Errore salvataggio turno: ' + err.message);
      console.error(err);
    } finally {
      this.loading = false;
    }
  }

  async deleteShift(index: number) {
    if (!confirm('Sei sicuro di voler eliminare questo turno?')) return;

    const shiftId = this.shifts[index].id;
    if (!shiftId) return;

    this.loading = true;
    try {
      const success = await this.shiftService.delete(shiftId);
      if (!success) throw new Error('Eliminazione fallita');
      alert('Turno eliminato con successo!');
    } catch (err: any) {
      alert('Errore eliminazione turno: ' + err.message);
      console.error(err);
    } finally {
      this.loading = false;
    }
  }

  async toggleShiftActive(index: number) {
    const shift = this.shifts[index];
    const newActiveState = !shift.is_active;

    if (!confirm(`Sei sicuro di voler ${newActiveState ? 'attivare' : 'disattivare'} il turno "${shift.name}"?`)) {
      return;
    }

    this.loading = true;
    try {
      const success = await this.shiftService.update(shift.id, { is_active: newActiveState });
      if (!success) throw new Error('Operazione fallita');
      alert(`Turno "${shift.name}" ${newActiveState ? 'attivato' : 'disattivato'} con successo!`);
    } catch (err: any) {
      alert(`Errore: ${err.message}`);
      console.error(err);
    } finally {
      this.loading = false;
    }
  }

  isCurrentShiftValid(): boolean {
    return !!(
      this.currentShift?.name &&
      this.currentShift?.start_time &&
      this.currentShift?.end_time &&
      this.currentShift?.days_of_week?.length > 0
    );
  }

  closeShiftModal() {
    this.showShiftModal = false;
    this.editingShift = null;
  }

  toggleCurrentShiftDay(dayIndex: number, event: Event) {
    const checked = (event.target as HTMLInputElement).checked;
    const dayNumber = dayIndex + 1;

    if (checked) {
      if (!this.currentShift.days_of_week.includes(dayNumber)) {
        this.currentShift.days_of_week.push(dayNumber);
      }
    } else {
      this.currentShift.days_of_week = this.currentShift.days_of_week.filter(d => d !== dayNumber);
    }
  }

  isDaySelected(shiftDays: number[], dayIndex: number): boolean {
    return shiftDays.includes(dayIndex + 1);
  }

  // ==================== PHOTO MANAGEMENT ====================

  triggerFileInput(slotIndex: number): void {
    this.currentSlotIndex = slotIndex;
    this.fileInput.nativeElement.click();
  }

  onPhotoFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (!input.files?.length || this.currentSlotIndex === null || !this.restaurantId) return;

    const file = input.files[0];
    const slotIndex = this.currentSlotIndex;
    this.currentSlotIndex = null;
    input.value = '';

    this.onPhotoFileSelect(file, slotIndex);
  }

  async onPhotoFileSelect(file: File, slotIndex: number) {
    if (!this.restaurantId) return;

    if (file.size > 10 * 1024 * 1024) {
      alert('File troppo grande (max 10MB)');
      return;
    }
    if (!file.type.startsWith('image/')) {
      alert('Solo file immagine sono permessi');
      return;
    }

    this.loadingPhotos = true;
    try {
      const displayOrder = slotIndex + 1;

      const uploadResult = await this.supabaseService.uploadRestaurantPhoto(
        this.restaurantId,
        file,
        displayOrder
      );

      if (!uploadResult) throw new Error('Upload fallito');

      const photoRecord = await this.supabaseService.saveRestaurantPhotoRecord({
        restaurant_id: this.restaurantId,
        file_path: uploadResult.filePath,
        display_order: displayOrder
      });

      if (!photoRecord) throw new Error('Salvataggio record fallito');

      this.photos[slotIndex] = {
        ...photoRecord,
        url: uploadResult.publicUrl
      };

    await this.syncCoverImage();
    this.triggerAutoSave();
    alert(`Foto ${displayOrder} caricata con successo!`);
    } catch (error: any) {
      console.error('Errore upload foto:', error);
      alert('Errore durante l\'upload: ' + error.message);
    } finally {
      this.loadingPhotos = false;
    }
  }

  async deletePhoto(slotIndex: number) {
    if (!this.restaurantId) return;

    const photo = this.photos[slotIndex];
    if (!photo || !confirm('Sei sicuro di voler eliminare questa foto?')) return;

    this.loadingPhotos = true;
    try {
      await this.supabaseService.deleteRestaurantPhoto(photo.id, photo.file_path);
      this.photos[slotIndex] = null;
      await this.syncCoverImage();
      this.triggerAutoSave();
      alert('Foto eliminata con successo!');
    } catch (error: any) {
      console.error('Errore eliminazione foto:', error);
      alert('Errore durante l\'eliminazione: ' + error.message);
    } finally {
      this.loadingPhotos = false;
    }
  }

  async onPhotoOrderChange(slotIndex: number, event: Event): Promise<void> {
    const select = event.target as HTMLSelectElement;
    const newOrder = Number(select.value);

    if (newOrder < 1 || newOrder > 8) {
      alert('Ordine non valido. Deve essere tra 1 e 8.');
      const photo = this.photos[slotIndex];
      if (photo) select.value = photo.display_order.toString();
      return;
    }

    const photo = this.photos[slotIndex];
    if (!photo) {
      alert('Nessuna foto in questo slot');
      return;
    }

    if (photo.display_order === newOrder) return;

    const oldOrder = photo.display_order;

    try {
      this.loadingPhotos = true;

      const photoAtNewOrder = this.photos.find(p => p && p.display_order === newOrder);

      if (photoAtNewOrder) {
        await Promise.all([
          this.supabaseService.updatePhotoOrder(photo.id, newOrder),
          this.supabaseService.updatePhotoOrder(photoAtNewOrder.id, oldOrder)
        ]);
        photo.display_order = newOrder;
        photoAtNewOrder.display_order = oldOrder;
      } else {
        await this.supabaseService.updatePhotoOrder(photo.id, newOrder);
        photo.display_order = newOrder;
      }

      this.reorganizePhotosByOrder();
      await this.syncCoverImage();
      this.triggerAutoSave();
      console.log('✅ Ordine aggiornato');
    } catch (error: any) {
      console.error('❌ Errore aggiornamento ordine:', error);
      alert('Errore durante l\'aggiornamento: ' + error.message);
      select.value = oldOrder.toString();
      photo.display_order = oldOrder;
    } finally {
      this.loadingPhotos = false;
    }
  }

  private reorganizePhotosByOrder() {
    const sortedPhotos = this.photos
      .filter(p => p !== null)
      .sort((a, b) => a!.display_order - b!.display_order);

    const newArray: (RestaurantPhoto | null)[] = Array(8).fill(null);
    sortedPhotos.forEach(photo => {
      const index = photo!.display_order - 1;
      if (index >= 0 && index < 8) newArray[index] = photo;
    });
    this.photos = newArray;
  }

  openPhoto(photo: RestaurantPhoto | null, index: number): void {
    if (photo?.url) {
      this.fullscreenPhoto = photo.url;
      this.currentPhotoIndex = index;
    }
  }

  closeFullscreenPhoto() {
    this.fullscreenPhoto = null;
    this.currentPhotoIndex = null;
  }

  navigateFullscreenPhoto(direction: 'prev' | 'next') {
    if (this.currentPhotoIndex === null || !this.photos) return;

    let nextIndex = direction === 'next'
      ? this.currentPhotoIndex + 1
      : this.currentPhotoIndex - 1;

    if (nextIndex < 0) nextIndex = this.photos.length - 1;
    if (nextIndex >= this.photos.length) nextIndex = 0;

    let foundPhoto = false;
    let attempts = 0;

    while (!foundPhoto && attempts < this.photos.length) {
      const photo = this.photos[nextIndex];
      if (photo?.url) {
        this.fullscreenPhoto = photo.url;
        this.currentPhotoIndex = nextIndex;
        foundPhoto = true;
      } else {
        nextIndex = direction === 'next' ? nextIndex + 1 : nextIndex - 1;
        if (nextIndex < 0) nextIndex = this.photos.length - 1;
        if (nextIndex >= this.photos.length) nextIndex = 0;
        attempts++;
      }
    }
  }

  onImageError(event: Event, slotIndex: number): void {
    const img = event.target as HTMLImageElement;
    console.error(`Errore caricamento immagine slot ${slotIndex}:`, img.src);
    img.style.display = 'none';

    const container = img.parentElement;
    if (container) {
      const errorDiv = document.createElement('div');
      errorDiv.className = 'error-placeholder';
      errorDiv.style.cssText = 'width: 100%; height: 100%; display: flex; align-items: center; justify-content: center; color: var(--danger); font-size: 12px;';
      errorDiv.textContent = 'Errore caricamento';
      container.appendChild(errorDiv);
    }
  }

  get loadedPhotosCount(): number {
    return this.photos.filter(p => p !== null).length;
  }

  get hasMultiplePhotos(): boolean {
    return this.loadedPhotosCount > 1;
  }

  trackByIndex(index: number): number {
    return index;
  }

  async toggleRestaurantActive() {
    if (!this.restaurantId) return;

    const newValue = this.settingsForm.get('is_active')?.value as boolean;
    const oldValue = !newValue;

    if (!newValue) {
      const confirmed = confirm(
        'Sei sicuro di voler disattivare il ristorante?\n\n' +
        'I clienti non potranno più vederlo né effettuare ordini. ' +
        'L\'account verrà eliminato automaticamente dopo 24 mesi di inattività.'
      );
      if (!confirmed) {
        this.settingsForm.patchValue({ is_active: oldValue }, { emitEvent: false });
        return;
      }
    }

    this.loading = true;
    try {
      await this.restaurantService.updateRestaurant(this.restaurantId, {
        is_active: newValue,
        deactivated_at: newValue ? null : new Date().toISOString()
      } as any);

      this.triggerAutoSave();
      alert(newValue
        ? 'Ristorante riattivato! Ora è visibile ai clienti.'
        : 'Ristorante disattivato correttamente.'
      );
    } catch (err: any) {
      alert('Errore: ' + err.message);
      this.settingsForm.patchValue({ is_active: oldValue }, { emitEvent: false });
    } finally {
      this.loading = false;
    }
  }

  togglePayment(event: any) {
  const payments = this.settingsForm.get('additional_info.accepted_payments')?.value || [];
  const value = event.target.value;
  if (event.target.checked) {
    if (!payments.includes(value)) {
      payments.push(value);
    }
  } else {
    const index = payments.indexOf(value);
    if (index > -1) {
      payments.splice(index, 1);
    }
  }
  this.settingsForm.get('additional_info.accepted_payments')?.setValue(payments);
}

isPaymentSelected(value: string): boolean {
  const payments = this.settingsForm.get('additional_info.accepted_payments')?.value;
  return payments ? payments.includes(value) : false;
}

toggleCuisine(event: any) {
  const cuisines = this.settingsForm.get('additional_info.cuisine_types')?.value || [];
  const value = event.target.value;
  if (event.target.checked) {
    if (!cuisines.includes(value)) {
      cuisines.push(value);
    }
  } else {
    const index = cuisines.indexOf(value);
    if (index > -1) {
      cuisines.splice(index, 1);
    }
  }
  this.settingsForm.get('additional_info.cuisine_types')?.setValue(cuisines);
}

isCuisineSelected(value: string): boolean {
  const cuisines = this.settingsForm.get('additional_info.cuisine_types')?.value;
  return cuisines ? cuisines.includes(value) : false;
}

async confirmDeleteRestaurant() {
  if (!this.restaurantId) return;
  this.deleteRestaurantLoading = true;
  this.deleteRestaurantError = '';
  try {
    const result = await this.authService.deleteRestaurant(this.restaurantId);
    if (!result.success) {
      this.deleteRestaurantError = result.error || 'Errore durante l\'eliminazione';
      return;
    }
    // authService.deleteRestaurant già gestisce il redirect se non ci sono più ristoranti
  } catch (err: any) {
    this.deleteRestaurantError = err.message || 'Errore sconosciuto';
  } finally {
    this.deleteRestaurantLoading = false;
    this.showDeleteRestaurantConfirm = false;
  }
}

private async syncCoverImage(): Promise<void> {
  if (!this.restaurantId) return;
  const coverPhoto = this.photos.find(p => p?.display_order === 1);
  const coverUrl = coverPhoto?.url ?? null;
  await this.supabaseService.getSupabaseClient()
    .from('restaurants')
    .update({ cover_image_url: coverUrl })
    .eq('id', this.restaurantId);
}

async setCoverPhoto(photo: RestaurantPhoto): Promise<void> {
  if (!this.restaurantId) return;
  this.loadingPhotos = true;
  try {
    await this.supabaseService.getSupabaseClient()
      .from('restaurants')
      .update({ cover_image_url: photo.url })
      .eq('id', this.restaurantId);

    this.currentCoverUrl = photo.url ?? null; // ← aggiungi questa riga

    alert('Foto impostata come copertina!');
  } catch (error: any) {
    console.error('Errore impostazione copertina:', error);
    alert('Errore: ' + error.message);
  } finally {
    this.loadingPhotos = false;
  }
}

}